    return ["Todos", ...new Set(dados.map(d =&gt; d.MODALIDADE))]
  } else {
    return [
      "Todos",
      ...new Set(
        dados
          .filter(d =&gt; d.CURSO === cursosDropdown)
          .map(d =&gt; d.MODALIDADE) // CORREÇÃO: era MODALIDE
      )
    ]
  }
}







